from flask import Flask, request, jsonify
import jwt
import requests

app = Flask(__name__)

BACKEND_SERVICES = {
    "service1": "http://localhost:5001",
    "service2": "http://localhost:5002",
}

def extract_bearer_token():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return None
    return auth_header.split(" ", 1)[1].strip()

def verify_jwt(token):
    try:
        decoded = jwt.decode(
            token,
            options={
                "require": ["exp", "iat", "sub"],
                "verify_signature": True,
                "verify_exp": True,
                "verify_iat": True,
            },
            algorithms=["HS256", "RS256"],
        )
        return decoded
    except jwt.PyJWTError:
        return None

def build_forward_headers(claims):
    headers = {}
    for header, value in request.headers.items():
        if header.lower() != "host":
            headers[header] = value
    headers["X-User-Sub"] = str(claims.get("sub", ""))
    headers["X-User-Claims"] = jwt.encode(claims, "gateway-forwarding", algorithm="HS256")
    return headers

@app.before_request
def authenticate():
    if request.path == "/health":
        return None

    token = extract_bearer_token()
    if not token:
        return jsonify({"error": "missing bearer token"}), 401

    claims = verify_jwt(token)
    if not claims:
        return jsonify({"error": "invalid token"}), 401

    request.claims = claims
    return None

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

@app.route("/<service>/<path:path>", methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
def gateway(service, path):
    backend = BACKEND_SERVICES.get(service)
    if not backend:
        return jsonify({"error": "unknown service"}), 404

    url = f"{backend}/{path}"
    headers = build_forward_headers(request.claims)

    try:
        resp = requests.request(
            method=request.method,
            url=url,
            headers=headers,
            params=request.args,
            data=request.get_data(),
            cookies=request.cookies,
            allow_redirects=False,
            timeout=30,
        )
        excluded = {"content-encoding", "content-length", "transfer-encoding", "connection"}
        response_headers = [(k, v) for k, v in resp.raw.headers.items() if k.lower() not in excluded]
        return (resp.content, resp.status_code, response_headers)
    except requests.RequestException:
        return jsonify({"error": "backend unavailable"}), 502

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8080)